1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteInput {
9	  items: Item[];
10	}
11	
12	export interface QuoteResult {
13	  premium: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const DEFAULT_BASE_PREMIUM = 100;
18	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const CURSE_SURCHARGE_RATE = 0.5;
27	
28	function basePremiumFor(item: Item): number {
29	  const base = BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
30	  if (item.cursed) {
31	    return base + base * CURSE_SURCHARGE_RATE;
32	  }
33	  return base;
34	}
35	
36	const BLOCK_SIZE = 3;
37	const BLOCK_PREMIUM = 60;
38	
39	function groupByType(items: Item[]): Map<string, Item[]> {
40	  const groups = new Map<string, Item[]>();
41	  for (const item of items) {
42	    const group = groups.get(item.type) ?? [];
43	    group.push(item);
44	    groups.set(item.type, group);
45	  }
46	  return groups;
47	}
48	
49	function basePremiumForGroup(group: Item[]): number {
50	  if (group.length === BLOCK_SIZE) {
51	    return BLOCK_PREMIUM;
52	  }
53	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
54	}
55	
56	export function quote(input: QuoteInput): QuoteResult {
57	  const groups = [...groupByType(input.items).values()];
58	  const basePremium = groups.reduce(
59	    (sum, group) => sum + basePremiumForGroup(group),
60	    0,
61	  );
62	
63	  return { premium: basePremium + PROCESSING_FEE };
64	}
